import re
text = open('_response.md').read()
blocks = re.findall(r'```mermaid\n(.*?)```', text, re.DOTALL)
lines = text.split('\n')
starts=[i+1 for i,l in enumerate(lines) if l.strip()=='```mermaid']

REAL_ISSUES=[]
for bi,(b,start) in enumerate(zip(blocks,starts)):
    blines=b.split('\n')
    for j,bl in enumerate(blines):
        ln=start+1+j
        s=bl.strip()
        if not s: continue
        # 1) Cylinder label text: [( ... )] -- extract inner, check for breaking chars INSIDE the cylinder text
        for m in re.finditer(r'\[\((.*?)\)\]', bl):
            inner=m.group(1)
            for ch in '()[]{}:;/<>"\\':
                if ch in inner:
                    REAL_ISSUES.append((ln,f"cylinder text '{inner}' has breaking char '{ch}'",bl))
        # 2) subroutine [[ ... ]] inner text
        for m in re.finditer(r'\[\[(.*?)\]\]', bl):
            inner=m.group(1)
            for ch in '()[]{}:;/<>"\\':
                if ch in inner:
                    REAL_ISSUES.append((ln,f"subroutine text '{inner}' has breaking char '{ch}'",bl))
        # 3) plain rect [ ... ] (not cylinder/subroutine) inner text
        # remove cylinder & subroutine first
        tmp=re.sub(r'\[\(.*?\)\]','',bl)
        tmp=re.sub(r'\[\[.*?\]\]','',tmp)
        for m in re.finditer(r'\[([^\[\]]*)\]',tmp):
            inner=m.group(1)
            for ch in '(){}:;/<>"\\':
                if ch in inner:
                    REAL_ISSUES.append((ln,f"rect text '{inner}' has breaking char '{ch}'",bl))
        # 4) UNQUOTED edge labels |...| containing breaking chars (quoted is fine)
        for m in re.finditer(r'\|([^|]*)\|',bl):
            inner=m.group(1)
            if inner.startswith('"') and inner.endswith('"'):
                # quoted - check inner for nested unescaped quote or breaking that even quotes don't save
                core=inner[1:-1]
                for ch in '"':
                    if ch in core:
                        REAL_ISSUES.append((ln,f"quoted edge label has nested quote: '{inner}'",bl))
            else:
                for ch in '(){}:;/<>"\\':
                    if ch in inner:
                        REAL_ISSUES.append((ln,f"UNQUOTED edge label '{inner}' has breaking char '{ch}'",bl))
        # 5) subgraph title quoted? check unquoted subgraph with breaking chars
        sm=re.match(r'subgraph\s+(\w+)\[(.*?)\]',s)
        if sm:
            title=sm.group(2)
            if not (title.startswith('"') and title.endswith('"')):
                for ch in '(){}:;/<>':
                    if ch in title:
                        REAL_ISSUES.append((ln,f"unquoted subgraph title '{title}' has '{ch}'",bl))

if REAL_ISSUES:
    print("REAL POTENTIAL ISSUES:")
    for ln,desc,bl in REAL_ISSUES:
        print(f"  L{ln}: {desc}")
        print(f"        {bl.strip()}")
else:
    print("NO REAL breaking-char issues found (quoted edge labels + shape-delimiter parens are valid Mermaid).")
